+import { object } from "./constructs.ts";
+import { formatMessage } from "./message.ts";
+import { withDefault } from "./modifiers.ts";
+import { conditionalOption, option, requiredWhen } from "./primitives.ts";
+import { parseSync, suggestSync } from "./parser.ts";
+import { boolean, string } from "./valueparser.ts";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional option dependencies", () => {
+  it("resolves object keys and option names through wrappers", () => {
+    const parser = object({
+      enabled: withDefault(option("--enabled"), false),
+      output: withDefault(
+        option("--output", string(), { dependsOn: { option: "--enabled" } }),
+        "default",
+      ),
+    });
+
+    assert.deepEqual(parseSync(parser, ["--enabled", "--output", "file"]), {
+      success: true,
+      value: { enabled: true, output: "file" },
+    });
+  });
+
+  it("supports value, anyOf, and allOf conditions", () => {
+    const parser = object({
+      mode: option("--mode", string()),
+      verbose: option("--verbose"),
+      output: conditionalOption(
+        { allOf: [{ option: "mode", value: "json" }, { option: "--verbose" }] },
+        "--output",
+        string(),
+      ),
+    });
+
+    assert.ok(parseSync(parser, ["--mode", "json", "--verbose", "--output", "x"]).success);
+    assert.ok(!parseSync(parser, ["--mode", "text", "--output", "x"]).success);
+  });
+
+  it("hides optional dependencies from suggestions but still accepts them", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      output: option("--output", string(), { dependsOn: { option: "enabled" } }),
+    });
+
+    assert.deepEqual(suggestSync(parser, ["--o"]), []);
+    assert.ok(parseSync(parser, ["--output", "file"]).success);
+  });
+
+  it("rejects a dependent option when its explicitly supplied dependee is falsy", () => {
+    const parser = object({
+      enabled: option("--enabled", boolean()),
+      output: option("--output", string(), { dependsOn: { option: "enabled" } }),
+    });
+
+    assert.ok(!parseSync(parser, ["--enabled=false", "--output", "file"]).success);
+  });
+
+  it("reports unmet required dependencies with the dependee flag and value", () => {
+    const parser = object({
+      mode: option("--mode", string()),
+      output: requiredWhen({ option: "mode", value: "json" }, "--output", string()),
+    });
+    const result = parseSync(parser, ["--output", "file"]);
+
+    assert.ok(!result.success);
+    if (!result.success) {
+      const error = formatMessage(result.error);
+      assert.ok(error.includes("requires option"));
+      assert.ok(error.includes("--mode"));
+      assert.ok(error.includes("json"));
+    }
+  });
+
+  it("uses the specified empty compound semantics and missing keys", () => {
+    const parser = object({
+      all: option("--all", { dependsOn: { allOf: [] } }),
+      any: option("--any", { dependsOn: { anyOf: [] } }),
+      missing: option("--missing", { dependsOn: { option: "absent" } }),
+    });
+
+    assert.ok(parseSync(parser, ["--all"]).success);
+    assert.ok(parseSync(parser, ["--any"]).success);
+    assert.deepEqual(suggestSync(parser, ["--"]), [{ kind: "literal", text: "--all" }]);
+  });
+});
