+function getOptionDependency(usage: Usage): OptionDependency | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn) return term.dependsOn;
+    if (term.type === "optional" || term.type === "multiple") {
+      const dependency = getOptionDependency(term.terms);
+      if (dependency) return dependency;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const dependency = getOptionDependency(terms);
+        if (dependency) return dependency;
+      }
+    }
+  }
+  return undefined;
+}
+
+function getOptionNames(usage: Usage): readonly string[] {
+  const names: string[] = [];
+  for (const term of usage) {
+    if (term.type === "option") names.push(...term.names);
+    else if (term.type === "optional" || term.type === "multiple") {
+      names.push(...getOptionNames(term.terms));
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) names.push(...getOptionNames(terms));
+    }
+  }
+  return names;
+}
