 */
async function* suggestArgumentAsync<T>(
  valueParser: ValueParser<Mode, T>,
  hidden: boolean,
  prefix: string,
  dependencyRegistry: DependencyRegistryLike | undefined,
): AsyncGenerator<Suggestion> {
  if (hidden) return;

